class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        long long best = 0;
        for (int l = 0; l < n; ++l) {
            vector<long long> dp(k + 1, 0);
            for (int r = l; r < n; ++r) {
                vector<long long> ndp(k + 1, 0);
                long long v = nums[r];
                for (int used = 0; used <= k; ++used) {
                    ndp[used] = gcd(dp[used], v);
                    if (used > 0) {
                        ndp[used] = max(ndp[used], gcd(dp[used - 1], v * 2));
                    }
                }
                for (int used = 0; used <= k; ++used) {
                    best = max(best, ndp[used] * (r - l + 1));
                }
                dp.swap(ndp);
            }
        }
        return best;
    }
};
